import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as a,a as s}from"./app-0abf0765.js";const t={},o=s(`<h1 id="null-referenciak" tabindex="-1"><a class="header-anchor" href="#null-referenciak" aria-hidden="true">#</a> null referenciák</h1><div class="hint-container note"><p class="hint-container-title">Röviden</p><ul><li>A típusok tartalmazhatnak olyan referenciákat, amely semmire sem mutatnak: <code>null</code>, ami egy objektum hiányát jelenti.</li></ul></div><p>A referencia típusú változók, például a <code>string</code>-ek, a tömbök (<code>array</code>-ek) és az osztályok (<code>class</code>-ok) nem tárolják az adatokat közvetlenül a változókban. A legtöbbször ezek a referenciák egy adott objektumra mutatnak, de néhány esetben az érték hiányát jelző referenciák. Ezt <code>null</code>-referenciának nevezzük. A kódban a <code>null</code> referenciát a <code>null</code> kulcsszóval használhatjuk:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name"><span class="token keyword">string</span></span> name <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>A <code>null</code> referencia akkor hasznos ha előfordulhat olyan, hogy nem áll rendelkezésünkre adat.</p><div class="hint-container tip"><p class="hint-container-title">Képzeljünk el egy játékot</p><p>Amelyben egy olyan karaktert irányítunk, aki be tud üllni egy járműbe és vezetni tudja azt. A járműnek lehet egy <code>Character driver;</code> mezője, amely megmutatja, hogy éppen melyik karakter ül vezetőülésben. Ettől függetlenül a vezetőülés lehet, hogy üres, amit úgy lehet ábrázolni, hogy a <code>driver</code> egy <code>null</code> referenciát tartalmaz. <code>null</code> <strong>a referencia típusok alapértelmezett értéke.</strong></p></div><p>A <code>null</code> értékek használata azonban nem marad következmények nélkül. Nézzük meg ezt a kódot:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name"><span class="token keyword">string</span></span> name <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span>name<span class="token punctuation">.</span>Length<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>Ez a kód összeomlik, mert egy nem létező karakterlánc hosszát próbálja lekérdezni. Ezt a hibát könnyű észrevenni, mivel a <code>name</code> mindig <code>null;</code> más helyzetekben kevésbé nyilvánvaló:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name"><span class="token keyword">string</span></span> name <span class="token operator">=</span> Console<span class="token punctuation">.</span><span class="token function">ReadLine</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Visszatérhet null-al!</span>
Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span>name<span class="token punctuation">.</span>Length<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Vajon a <code>ReadLine()</code> karakterláncot adott vissza nekünk, vagy <code>null</code> értéket?</strong> Valószínűleg még nem találkoztunk vele, de bizonyos helyzetekben előfordulhat, hogy a <code>ReadLine()</code> <code>null</code> értéket ad vissza. (<em>Próbáljuk meg a <strong>Ctrl + Z</strong> billentyűkombinációt megnyomni, amikor a számítógép arra vár, hogy valamit beírjunk.</em>) A lehetőség, hogy <code>null</code> lehet, arra kényszerít minket, hogy óvatosan használjuk.</p><h2 id="null-vagy-nem-null" tabindex="-1"><a class="header-anchor" href="#null-vagy-nem-null" aria-hidden="true">#</a> <code>null</code> vagy nem <code>null</code>?</h2><p>Amikor referencia típusú változókról van szó, érdemes megállni egy pillanatra és átgondolni, hogy a <code>null</code> érték lehetőséges legyen-e?!</p><p>Néhány módszert fogunk látni a <code>null</code> érték ellenőrzésére rövidesen:</p><ul><li><p>Abban az esetben ha a <code>null</code> érték megengedett, érdemes ellenőrizni a <code>null</code> értéket, mielőtt használnánk azokat a tagokat (<em>metódusokat</em>, <em>tulajdonságokat</em>, <em>mezőket</em>, stb.).</p></li><li><p>Abban az esetben ha a <code>null</code> érték nem megengedett, ellenőriznünk kell az összes értéket, amit hozzárendelünk, hogy biztosak legyünk abban, hogy véletlenül sem rendelünk <code>null</code> értéket hozzá.</p></li></ul><p>Miután eldöntöttük, hogy egy változónak megengedjük-e a <code>null</code> értéket, ezt a döntést jelezni akarjuk a kódunkban. Bármely referencia-típusú változó végén lehet egy <code>?</code> vagy nem. Az <code>?</code> azt jelenti, hogy tartalmazhat <code>null</code> értéket.</p><p>Például:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name"><span class="token keyword">string</span><span class="token punctuation">?</span></span> name <span class="token operator">=</span> Console<span class="token punctuation">.</span><span class="token function">ReadLine</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// Visszatérhet null-al!</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>A fenti kódban a <code>name</code> típusa most <code>string?</code>, ami azt jelzi, hogy bármilyen érvényes <code>string</code> példányt tartalmazhat, de lehet <code>null</code> is. A <code>?</code> nélkül, ahogy eddig is használtuk azt mondja meg, hogy a <code>null</code> nem opció.</p><p>Eddig figyelmen kívül hagytuk a <code>null</code> lehetőségét, sőt eddig probléma nélkül megúsztuk. Az összes eddig látott kódunkban az egyetlen valós veszélyt az jelentette, hogy a <code>Console.ReadLine();</code> <code>null</code> értéket adhatott volna vissza és ezt nem kezeltük.</p><div class="hint-container info"><p class="hint-container-title">Viszont eddig...</p><p>nem nyomtuk meg a <strong>Ctrl + Z</strong> billentyűkombinációt, így ez a probléma nem merült fel. 😄</p></div><p>Még ha elő is jött volna, általában a bemenetet vagy közvetlenül megjelenítettük vagy más típusba konvertáltuk és mind a <code>Console.WriteLine();</code>, mind a <code>Convert.ToInt32();</code> (<em>és a többi metódus</em>) biztonságosan kezeli le a <code>null</code> értéket.</p><p>De mostantól kezdve sokkal nagyobb valószínűséggel találkozunk <code>null</code>-al kapcsolatos problémákkal, ezért itt az ideje, hogy óvatosabbak legyünk és minden egyes referencia-típusú változó esetében szándékosan döntsünk arról, hogy a <code>null</code> megengedett-e vagy sem.</p><p>Ha helyesen alkalmazzuk (<em>vagy kihagyjuk</em>) a <code>?</code>-t a változóinkra, akkor a fordító segítségét is igénybe vehetjük a <code>null</code> ellenőrzéséhez. Ez a segítség rendkívül hasznos. Könnyen előfordulhat, hogy magunktól valamit kihagyunk. Ha a fordító segít észrevenni a <code>null</code>-al kapcsolatos problémákat, nem fogunk sokat kihagyni. A másik előnye természetesen az, hogy a kódból egyértelműen kiderül, hogy a <code>null</code> érvényes lehetőség-e egy változóra.</p><p>Példáinkban eddig csak <code>string</code>-eket használtunk, de ez minden hivatkozási típusra vonatkozik, beleértve a tömböket és bármilyen általunk készített osztályt is. Hasonlót tehetnénk a <code>Score</code> és <code>Rectangle</code> osztályaink használatára is.</p><h2 id="null-ellenorzese" tabindex="-1"><a class="header-anchor" href="#null-ellenorzese" aria-hidden="true">#</a> <code>null</code> ellenőrzése</h2><p>Gyakran szükség lesz arra, hogy ellenőrizzük, hogy <code>null</code> érték-e az adott referencia. A <code>null</code> érték ellenőrzésének mechanizmusa egyszerű. A legegyszerűbb módja annak, hogy ellenőrizzük a <code>null</code> értéket, az egy referencia összehasonlítása a <code>null</code> literállal, ami egy <code>null</code> ellenőrzést jelent:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name"><span class="token keyword">string</span><span class="token punctuation">?</span></span> name <span class="token operator">=</span> Console<span class="token punctuation">.</span><span class="token function">ReadLine</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">if</span> <span class="token punctuation">(</span>name <span class="token operator">!=</span> <span class="token keyword">null</span><span class="token punctuation">)</span> 
<span class="token punctuation">{</span>
    Console<span class="token punctuation">.</span><span class="token function">WriteLine</span><span class="token punctuation">(</span><span class="token string">&quot;The name is not null.&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha egy változó azt jelzi, hogy a <code>null</code> érték lehetséges lehetőség, akkor érdemes <code>null</code> ellenőrzést végezni, mielőtt használnánk annak tagjait.</p><p>Fontos megjegyezni, hogy <strong>a fordítás után nincs különbség a <code>string?</code> és a <code>string</code> között</strong>. Ha figyelmen kívül hagyjuk a fordító által adott figyelmeztetéseket, amelyek segítenek a helyes megoldás megtalálásában, még egy egyszerű <code>string</code> (<em>a <code>?</code> nélkül</em>) is technikailag tartalmazhat <code>null</code> értéket.</p><h3 id="null-felteteles-operatorok-es" tabindex="-1"><a class="header-anchor" href="#null-felteteles-operatorok-es" aria-hidden="true">#</a> <code>null</code>-feltételes operátorok: <code>?.</code> és <code>?[]</code></h3><p>A <code>null</code>-ellenőrzéssel az egyik probléma az, hogy a későbbiekben következményei lehetnek.</p><p>Például:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">string</span><span class="token punctuation">?</span></span> <span class="token function">GetTopPlayerName</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token keyword">return</span> scoreManager<span class="token punctuation">.</span><span class="token function">GetScores</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">.</span>Name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>scoreManager</code> lehet <code>null</code>, a <code>GetScores()</code> <code>null</code>-át adhat vissza, vagy a tömb tartalmazhat <code>null</code> hivatkozást a 0 indexen. Ha ezek bármelyike <code>null</code>, a program összeomlik. Minden egyes lépésnél ellenőriznünk kell:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">string</span><span class="token punctuation">?</span></span> <span class="token function">GetTopPlayerName</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token keyword">if</span> <span class="token punctuation">(</span>scoreManager <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
    <span class="token class-name">Score<span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">?</span></span> scores <span class="token operator">=</span> scoreManager<span class="token punctuation">.</span><span class="token function">GetScores</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> 
   
    <span class="token keyword">if</span> <span class="token punctuation">(</span>scores <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
    <span class="token class-name">Score<span class="token punctuation">?</span></span> topScore <span class="token operator">=</span> scores<span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">;</span>
    
    <span class="token keyword">if</span> <span class="token punctuation">(</span>topScore <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token keyword">return</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
    
    <span class="token keyword">return</span> topScore<span class="token punctuation">.</span>Name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>A <code>null</code>-ellenőrzések miatt a kód nehezen olvasható. Elfedik az lényeges részeket.</p><p>Van egy másik lehetőség is: a <strong>null-feltételes operátorok</strong>. A <code>?.</code> és <code>?[]</code> operátorokat alkalmazhatjuk a <code>.</code> és <code>[]</code> helyett, hogy egyszerre ellenőrizzük a <code>null</code> értéket és hozzáférjünk a taghoz:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">string</span><span class="token punctuation">?</span></span> <span class="token function">GetTopPlayerName</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token keyword">return</span> scoreManager<span class="token punctuation">?.</span><span class="token function">GetScores</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">?</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">?.</span>Name<span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Mind a <code>?.</code>, mind a <code>?[]</code> kiértékeli az előtte lévő részt, hogy kiderüljön, <code>null</code>-e. Ha igen, akkor nem történik további kiértékelés és az egész kifejezés <code>null</code>-ára értékelődik. Ha nem <code>null</code>, akkor a kiértékelés úgy folytatódik, mintha egy normál <code>.</code> vagy <code>[]</code> operátor lett volna.</p><p>Ha a <code>scoreManager</code> <code>null</code>, akkor a fenti kód <code>null</code> értéket ad vissza anélkül, hogy meghívná a <code>GetScores</code> függvényt. Ha a <code>GetScores()</code> <code>null</code> értéket ad vissza, akkor a fenti kód <code>null</code> értéket ad vissza anélkül, hogy hozzáférne az 0. indexhez.</p><p>Ezek az operátorok nem fednek le minden nullával kapcsolatos forgatókönyvet - <em>néha szükség lesz a jó öreg <code>if (x == null)</code>-ra -</em>, de sok esetben megoldást jelenthetnek.</p><h3 id="a-null-osszefoglalo-operator" tabindex="-1"><a class="header-anchor" href="#a-null-osszefoglalo-operator" aria-hidden="true">#</a> A <code>null</code>-összefoglaló operátor: <code>??</code></h3><p>A null-összefoglaló operátor (<code>??</code>) - <em>coalescing operator</em> - szintén hasznos eszköz. Egy olyan kifejezést vesz, amely <code>null</code> lehet és egy olyan értéket vagy kifejezést ad meg, amelyet helyettesítő értékként használhatunk, ha <code>null</code>:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> <span class="token function">GetTopPlayerName</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// Többé nem kell megengedni a null -t.</span>
<span class="token punctuation">{</span>
    <span class="token keyword">return</span> scoreManager<span class="token punctuation">?.</span><span class="token function">GetScores</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">?</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">?.</span>Name <span class="token operator">??</span> <span class="token string">&quot;(not found)&quot;</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ha a <code>??</code> előtti kód nullára értékelődik, akkor a <code>&quot;(not found)&quot;</code> értékét fogja használni helyette.<br> Erre is van egy összetett hozzárendelési operátor:</p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token keyword">private</span> <span class="token return-type class-name"><span class="token keyword">string</span></span> <span class="token function">GetTopPlayerName</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
    <span class="token class-name"><span class="token keyword">string</span><span class="token punctuation">?</span></span> name <span class="token operator">=</span> scoreManager<span class="token punctuation">?.</span><span class="token function">GetScores</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">?</span><span class="token punctuation">[</span><span class="token number">0</span><span class="token punctuation">]</span><span class="token punctuation">?.</span>Name<span class="token punctuation">;</span>
    
    name <span class="token operator">??=</span> <span class="token string">&quot;(not found)&quot;</span><span class="token punctuation">;</span>
    
    <span class="token keyword">return</span> name<span class="token punctuation">;</span> <span class="token comment">// Nincs fordítói figyelmeztetés. A \`??=\` biztosítja, hogy valós értéket kapjunk.</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="a-null-t-megengedo-operator" tabindex="-1"><a class="header-anchor" href="#a-null-t-megengedo-operator" aria-hidden="true">#</a> A <code>null</code>-t megengedő operátor: <code>!</code></h3><p>A fordító igen alaposan elemzi, hogy mi lehet és mi nem lehet <code>null</code> és megfelelő figyelmeztetéseket ad nekünk. Hogy megszabaduljunk a fordítói figyelmeztetéstől, használhatjuk a null-megengedő operátort: <code>!</code>. Ez az operátor azt mondja a fordítónak: <strong>&quot;Tudom, hogy ez potenciális <code>null</code> problémának tűnik, de nem lesz az. Bízz bennem!&quot;</strong></p><div class="language-csharp line-numbers-mode" data-ext="cs"><pre class="language-csharp"><code><span class="token class-name"><span class="token keyword">string</span><span class="token punctuation">?</span></span> nullableString <span class="token operator">=</span> <span class="token keyword">null</span><span class="token punctuation">;</span>

<span class="token class-name"><span class="token keyword">string</span></span> nonNullableString <span class="token operator">=</span> nullableString<span class="token operator">!</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ebben a példában a <code>nullableString</code> változó <code>null</code> értéket kap. A <code>nonNullableString</code> változó azonban a <code>null</code>-t megengedő operátor (<code>!</code>) segítségével kijelenti, hogy biztosak vagyunk benne, hogy a <code>nullableString</code> változó nem lesz <code>null</code>. Ez lehetővé teszi a fordítónak, hogy átmenetileg figyelmen kívül hagyja a <code>null</code> hibákat és engedélyezze a kódnak, hogy futtatódjon.</p><p>Legyenünk óvatosak a használatával, mert ha a változó mégis <code>null</code> értéket kap, futási időben hibát fog dobni.</p>`,52),l=[o];function c(p,i){return e(),a("div",null,l)}const u=n(t,[["render",c],["__file","lesson8.html.vue"]]);export{u as default};
